#include <stdio.h>
#include <string.h>

int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    char buffer[128];
    // consume the newline after T
    fgets(buffer, sizeof(buffer), stdin);
    while(T--){
        if(!fgets(buffer, sizeof(buffer), stdin)) break;
        // remove trailing newline if present
        size_t len = strlen(buffer);
        if(len && buffer[len-1]=='\n') buffer[--len]='\0';
        int freq[26]={0};
        for(size_t i=0;i<len;++i) freq[buffer[i]-'a']++;
        int length=0, odd=0;
        for(int i=0;i<26;++i){
            length += (freq[i]/2)*2;
            if(freq[i]%2) odd=1;
        }
        if(odd) length+=1;
        printf("%d\n",length);
    }
    return 0;
}

