import sys

def longest_palindrome(s: str) -> int:
    freq = [0]*26
    for ch in s:
        freq[ord(ch)-97] += 1
    length = 0
    odd = False
    for cnt in freq:
        length += (cnt//2)*2
        if cnt%2:
            odd = True
    if odd:
        length += 1
    return length

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out = []
    for i in range(1, T+1):
        s = data[i].strip()
        out.append(str(longest_palindrome(s)))
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

