const fs = require('fs');
const lines = fs.readFileSync(0,'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++],10);
let results = [];
for(let t=0; t<T; ++t){
    const s = (lines[idx++]||'').trim();
    const freq = new Array(26).fill(0);
    for(let i=0;i<s.length;++i){
        freq[s.charCodeAt(i)-97]++;
    }
    let length = 0;
    let odd = false;
    for(const cnt of freq){
        length += Math.floor(cnt/2)*2;
        if(cnt%2) odd = true;
    }
    if(odd) length += 1;
    results.push(String(length));
}
console.log(results.join('\n'));

